############################################# ### Generated from PreTeXt source ### ### https://pretextbook.org ### ############################################# ## DBsubject() ## DBchapter() ## DBsection() ## Level() ## KEYWORDS() ## TitleText1() ## EditionText1() ## AuthorText1() ## Section1(not reported) ## Problem1(3.5.8.181) ## Author() ## Institution() ## Language(en-US)
DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "randomPerson.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ Context('Numeric'); $p = randomPerson(); do { $homework = random(60,90); $project = random(80,100); $midterm = random(70,90); $goal = list_random(70,80,90); $sol = 4*($goal - ($homework/3 + $project/6 + $midterm/4)); } until ($goal > 0 && $goal < 100);
############################################################ # Body ############################################################
BEGIN_PGML In one college math course, the final grade (out of [`100`] points) is calculated by adding one-third of the homework average, one-sixth of the class project score, one-fourth of the midterm score, and one-fourth of the final exam score.
[$p] has [$homework] for [$p->their] homework average, [$project] for [$p->their] class project score, and [$midterm] for [$p->their] midterm score. [$p->Their] goal is to finish the course with a final grade of [$goal]. What must [$p->they] score on the final exam?
[_]{$sol}{16}
END_PGML
############################################################ # End Problem ############################################################
ENDDOCUMENT();
